def compute_score():

    if len(ppt_diff.modified_slides) == 0:
        return "No slides were modified.", 0.0

    from pptx import Presentation
    from pptx.enum.text import PP_ALIGN

    def get_effective_alignment(paragraph, shape_or_cell):
        """Get the effective alignment using multiple detection methods"""
        from pptx.enum.text import PP_ALIGN

        # Method 1: Direct paragraph alignment
        if paragraph.alignment is not None:
            return paragraph.alignment

        # Method 2: Check paragraph properties in XML more thoroughly
        try:
            if hasattr(paragraph, '_p') and paragraph._p is not None:
                # Try multiple XML namespace approaches
                namespaces = {
                    'a': 'http://schemas.openxmlformats.org/drawingml/2006/main',
                    'p': 'http://schemas.openxmlformats.org/presentationml/2006/main'
                }

                # Look for pPr (paragraph properties) with different approaches
                pPr_elements = [
                    paragraph._p.find('.//a:pPr', namespaces),
                    paragraph._p.find('.//pPr'),
                    paragraph._p.find('.//{http://schemas.openxmlformats.org/drawingml/2006/main}pPr'),
                ]

                for pPr in pPr_elements:
                    if pPr is not None:
                        algn = pPr.get('algn')
                        if algn:
                            if algn == 'ctr':
                                return PP_ALIGN.CENTER
                            elif algn == 'l':
                                return PP_ALIGN.LEFT
                            elif algn == 'r':
                                return PP_ALIGN.RIGHT

                        # Also check for marL, marR attributes which might indicate center
                        marL = pPr.get('marL')
                        marR = pPr.get('marR')
                        if marL and marR and marL == marR:
                            return PP_ALIGN.CENTER
        except Exception as e:
            pass

        # Method 3: Check placeholder hierarchy more thoroughly
        try:
            if hasattr(shape_or_cell, 'placeholder_format') and shape_or_cell.placeholder_format:
                placeholder_idx = shape_or_cell.placeholder_format.idx

                # Get the slide layout
                if hasattr(shape_or_cell, 'part'):
                    slide_layout = shape_or_cell.part.slide_layout

                    # Check layout placeholders more thoroughly
                    for layout_shape in slide_layout.placeholders:
                        if layout_shape.placeholder_format.idx == placeholder_idx:
                            if layout_shape.has_text_frame:
                                # Check all paragraphs and their properties
                                for layout_para in layout_shape.text_frame.paragraphs:
                                    # Direct alignment check
                                    if layout_para.alignment is not None:
                                        return layout_para.alignment

                                    # Check XML properties of layout paragraph
                                    if hasattr(layout_para, '_p') and layout_para._p is not None:
                                        pPr = layout_para._p.find('.//{http://schemas.openxmlformats.org/drawingml/2006/main}pPr')
                                        if pPr is not None:
                                            algn = pPr.get('algn')
                                            if algn:
                                                if algn == 'ctr':
                                                    return PP_ALIGN.CENTER
                            break

                    # Check master placeholders more thoroughly
                    slide_master = slide_layout.slide_master
                    for master_shape in slide_master.placeholders:
                        if master_shape.placeholder_format.idx == placeholder_idx:
                            if master_shape.has_text_frame:
                                # Check all paragraphs and their properties
                                for master_para in master_shape.text_frame.paragraphs:
                                    # Direct alignment check
                                    if master_para.alignment is not None:
                                        return master_para.alignment

                                    # Check XML properties of master paragraph
                                    if hasattr(master_para, '_p') and master_para._p is not None:
                                        pPr = master_para._p.find('.//{http://schemas.openxmlformats.org/drawingml/2006/main}pPr')
                                        if pPr is not None:
                                            algn = pPr.get('algn')
                                            if algn:
                                                if algn == 'ctr':
                                                    return PP_ALIGN.CENTER
                            break
        except Exception as e:
            pass
        # Method 4: Check text frame level properties
        try:
            if hasattr(shape_or_cell, 'text_frame'):
                text_frame = shape_or_cell.text_frame
                # Check if there are any text frame level alignment properties
                if hasattr(text_frame, '_txBody') and text_frame._txBody is not None:
                    # Look for bodyPr or lstStyle elements that might contain alignment
                    bodyPr = text_frame._txBody.find('.//{http://schemas.openxmlformats.org/drawingml/2006/main}bodyPr')
                    if bodyPr is not None:
                        anchor = bodyPr.get('anchor')
                        if anchor == 'ctr':
                            return PP_ALIGN.CENTER
        except Exception as e:
            pass
        # Method 5: Check if shape position suggests center alignment
        try:
            if hasattr(shape_or_cell, 'left') and hasattr(shape_or_cell, 'width'):
                slide_width = 9144000  # Standard PowerPoint slide width in EMUs
                shape_left = shape_or_cell.left
                shape_width = shape_or_cell.width
                shape_center_x = shape_left + (shape_width / 2)
                slide_center_x = slide_width / 2

                # If shape is roughly centered horizontally, likely center-aligned
                center_tolerance = slide_width * 0.15  # 15% tolerance
                if abs(shape_center_x - slide_center_x) < center_tolerance:
                    return PP_ALIGN.CENTER
        except Exception as e:
            pass
        return PP_ALIGN.LEFT

    try:
        prs = Presentation(modified_ppt_path)
        slide = prs.slides[26] if len(prs.slides) >= 27 else None
        if not slide:
            return "Slide 27 not found in the presentation.", 0.0

        all_center = True
        non_center_cnt = 0
        total_text_items = 0

        for shape in slide.shapes:
            # Handle regular text frames
            if shape.has_text_frame and shape.text_frame.text.strip():  # Only process non-empty text frames
                # Check if this text frame is center-aligned (check all paragraphs)
                shape_is_center = True
                shape_has_content = False

                for paragraph in shape.text_frame.paragraphs:
                    if paragraph.text.strip():  # Only count non-empty paragraphs
                        shape_has_content = True
                        effective_alignment = get_effective_alignment(paragraph, shape)

                        # If any paragraph in the shape is not center-aligned, the shape fails
                        if effective_alignment != PP_ALIGN.CENTER:
                            shape_is_center = False
                            break

                if shape_has_content:  # Only count shapes that have actual content
                    total_text_items += 1

                    # Debug info
                    para_align = shape.text_frame.paragraphs[0].alignment if shape.text_frame.paragraphs else None
                    is_placeholder = hasattr(shape, 'placeholder_format') and shape.placeholder_format
                    placeholder_idx = shape.placeholder_format.idx if is_placeholder else "N/A"


                    if not shape_is_center:
                        all_center = False
                        non_center_cnt += 1

            # Handle tables
            elif shape.shape_type == 19:  # MSO_SHAPE_TYPE.TABLE = 19
                for row_idx, row in enumerate(shape.table.rows):
                    for col_idx, cell in enumerate(row.cells):
                        if cell.text_frame and cell.text_frame.text.strip():  # Only process non-empty cells
                            # Check if this cell is center-aligned (check all paragraphs)
                            cell_is_center = True

                            for paragraph in cell.text_frame.paragraphs:
                                if paragraph.text.strip():  # Only count non-empty paragraphs
                                    effective_alignment = get_effective_alignment(paragraph, cell)

                                    # If any paragraph in the cell is not center-aligned, the cell fails
                                    if effective_alignment != PP_ALIGN.CENTER:
                                        cell_is_center = False
                                        break

                            total_text_items += 1


                            if not cell_is_center:
                                all_center = False
                                non_center_cnt += 1

        if total_text_items == 0:
            return "No text elements found on slide 27.", 0.0

        if all_center:
            return "All text on slide 27 is center-aligned.", 1.0
        else:
            score = (total_text_items - non_center_cnt) / total_text_items
            return f"{non_center_cnt} out of {total_text_items} text element(s) not center-aligned on slide 27.", score

    except Exception as e:
        return f"Error: {e}", 0.0

def compute_score():
    # Check for modifications or additions/removals on slides other than 27
    changed = set()
    for s1, s2 in ppt_diff.modified_slides:
        if s1.slide_number != 27:
            changed.add(s1.slide_number)
    for s in ppt_diff.added_slides:
        if s.slide_number != 27:
            changed.add(s.slide_number)
    for s in ppt_diff.removed_slides:
        if s.slide_number != 27:
            changed.add(s.slide_number)
    if changed:
        return f"Slides other than 27 were changed: {sorted(changed)}", 0.0
    return "Only slide 27 was modified.", 1.0

def compute_score():
    slide27_id = None
    for s in ppt_diff.modified_slides + [(s, s) for s in ppt_diff.added_slides]:
        if s[1].slide_number == 27:
            slide27_id = s[1].slide_id
            break
    if slide27_id is None:
        # Try to infer: fallback by index if slide_id missing
        try:
            slide27_id = ppt_diff.modified_slides[26][1].slide_id
        except:
            pass
    added = [a for a in ppt_diff.added_animations if a.slide_id == slide27_id]
    removed = [a for a in ppt_diff.removed_animations if a.slide_id == slide27_id]
    if added or removed:
        return f"Animations added/removed on slide 27: added={len(added)}, removed={len(removed)}", 0.0
    return "No animations added or removed on slide 27.", 1.0

